<p class="wp-block-paragraph">This article is a comprehensive guide for students considering studying in Turkey. By evaluating the costs and benefits of on-campus and off-campus living, you can choose the most suitable option.</p>', '$.wp_published_at', '2025-08-27T14:43:49Z', '$.wp_modified_at', '2026-03-15T18:51:54Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/08/turkey-student-visa-financial-qualification-conditions-and-application-sureci.webp","alt":"On-campus and off-campus living cost comparison for students in Turkey showing accommodation, food, and transportation expenses.","title":"turkey-student-visa-financial-qualification-conditions-and-application-sureci"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'en' AND "slug" = 'cost-of-living-on-and-off-campus-in-turkey' );
