study.com/turkiyede-etnik-gruplar-kulturel-miras/#webpage"},"image":{"@id":"https://roadtostudy.com/wp-content/uploads/2025/09/ethnic-groups-and-cultural-heritage-in-turkey.webp"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/turkiyede-etnik-gruplar-kulturel-miras/#webpage"}}]}]}', "content_html" = '<div class="dad65929">
